ps.pstext:
if !IsFeatureImplemented(FEAT_SME_TMOP) then EndOfDecode(Decode_UNDEF); end;
let n : integer = UInt(Zn::'0');
let m : integer = UInt(Zm);
let k : integer = UInt('1'::K::'1'::Zk);
let index : integer = UInt(i2);
let da : integer = UInt(ZAda);
let op1_unsigned : boolean = FALSE;
let op2_unsigned : boolean = FALSE;

CheckStreamingSVEAndZAEnabled();
let VL : integer{} = CurrentVL();
let dim : integer{} = VL DIV 32;
let csize : integer{} = VL DIV 4;
let op2 : bits(VL) = Z{}(m);
let op3 : bits(VL) = Z{}(k);
let ctrl : bits(csize) = op3[index*:csize];
let op4 : bits(dim*dim*32) = ZAtile{}(da, 32);
var result : bits(dim*dim*32);

for row = 0 to dim-1 do
    for col = 0 to dim-1 do
        var erow : array [[4]] of bits(8);
        var ecol : array [[4]] of bits(8);
        for j = 0 to 3 do
            erow[[j]] = Zeros{8};
            ecol[[j]] = op2[(4*col + j)*:8];
        end;
        for r = 0 to 1 do
            let op1 : bits(VL) = Z{}(n+r);
            var i : integer = 0;
            for e = 0 to 3 do
                if i < 2 && ctrl[(8*col + 4*r + e)*:1] == '1' then
                    erow[[2*r + i]] = op1[(4*row + e)*:8];
                    i = i + 1;
                end;
            end;
        end;
        var sum : bits(32) = op4[(row*dim+col)*:32];
        for j = 0 to 3 do
            let erowval : integer = if op1_unsigned then UInt(erow[[j]]) else SInt(erow[[j]]);
            let ecolval : integer = if op2_unsigned then UInt(ecol[[j]]) else SInt(ecol[[j]]);
            sum = sum + (erowval * ecolval);
        end;
        result[(row*dim+col)*:32] = sum;
    end;
end;
ZAtile{dim*dim*32}(da, 32) = result;
